import{_ as a,o as t,c as r,an as n}from"./chunks/framework.D5fFzH9V.js";const u=JSON.parse('{"title":"Pricing","description":"Pricing model for pentests, including day rates, typical project ranges, and discount rules.","frontmatter":{"description":"Pricing model for pentests, including day rates, typical project ranges, and discount rules."},"headers":[],"relativePath":"pricing.md","filePath":"pricing.md"}'),o={name:"pricing.md"};function i(s,e,c,d,l,p){return t(),r("div",null,[...e[0]||(e[0]=[n('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /pricing.md for this page in Markdown format</div><h1 id="pricing" tabindex="-1">Pricing <a class="header-anchor" href="#pricing" aria-label="Permalink to &quot;Pricing&quot;">​</a></h1><p>If a real attacker spends more time than a pentester, he might find vulnerabilities that the tester did not find before. This is the timebox principle.</p><p>That&#39;s why (serious) pentests are always charged according to time spent (usually in person-days). One person-day costs € 1.600,-. From 20 person-days we give a 15% discount (€ 1.360,-).</p><h2 id="and-what-does-a-pentest-really-cost-now" tabindex="-1">And what does a Pentest really cost now? <a class="header-anchor" href="#and-what-does-a-pentest-really-cost-now" aria-label="Permalink to &quot;And what does a Pentest really cost now?&quot;">​</a></h2><p>We estimate the effort for a pentest in advance in a scoping meeting (for more information, see <a href="./before-pentests">Before the pentest</a>). Here are a few guidelines on what you can usually expect.</p><ul><li><strong>Web Applications</strong>: € 5.000-16.000</li><li><strong>Microsoft Active Directory</strong>: € 12.000-20.000</li><li><strong>External Infrastructure</strong>: € 8.000-11.000</li></ul><h2 id="discounts" tabindex="-1">Discounts <a class="header-anchor" href="#discounts" aria-label="Permalink to &quot;Discounts&quot;">​</a></h2><ul><li>From 20 person days we give a 15% discount.</li><li>In the Academia area we offer a very attractive daily rate of € 1.200,-.</li><li>We are currently launching a <a href="./pro-bono-pentests">pro bono programme</a>.</li></ul><p>Otherwise, we ask for your understanding that we do not grant discounts. Negotiating talent should not be a price-determining factor. In return, you can expect full fairness and transparency from us.</p><h2 id="partner" tabindex="-1">Partner <a class="header-anchor" href="#partner" aria-label="Permalink to &quot;Partner&quot;">​</a></h2><p>If we are unable to offer a service, we are happy to recommend competent companies. We are also pleased when we are recommended by others.</p><p>We never <strong>charge</strong> a recommendation fee or any other fee for recommendations. Likewise, we do not pay any fees for referrals. This means that our recommendations are always based on the quality of the recommended company and not on the fee.</p><p>If a security company concludes a contract directly with the end customer and engages us as a subcontractor, we charge 85% of the end customer&#39;s price, but at least a daily rate of € 1000. Our partner is then responsible for passing on the provisions from our <a href="/service-description">service description</a> to the end customer.</p>',14)])])}const f=a(o,[["render",i]]);export{u as __pageData,f as default};
